        elif self.separate_codebook_per_head:
            dist_einops_eq = 'c b n l -> b l n c'
        else:
            dist_einops_eq = '1 (b h) n l -> b l n h'

        ce_loss = F.cross_entropy(
            rearrange(distances, dist_einops_eq, b = shape[0]),
            codes,
            ignore_index = -1
        )

